1	// Package evidence provides shared primitives for assembling LLM prompts
2	// from bounded evidence sources. Every prompt-building call site in DDx
3	// must use these primitives so that no prompt has unbounded size.
4	//
5	// FEAT-022 §1 / §1a. Stage A1.
6	package evidence
7	
8	// Built-in default caps. These are intentionally permissive on land
9	// (FEAT-022 Non-Functional / Backward compatibility) so existing
10	// behavior does not change. Stage F telemetry informs later tightening.
11	const (
12		DefaultMaxPromptBytes       = 4 * 1024 * 1024 // 4 MiB
13		DefaultMaxInlinedFileBytes  = 512 * 1024      // 512 KiB
14		DefaultMaxDiffBytes         = 2 * 1024 * 1024 // 2 MiB
15		DefaultMaxGoverningDocBytes = 256 * 1024      // 256 KiB
16	)
17	
18	// Caps is the resolved byte-cap set used by an evidence-assembly call site.
19	// All caps are byte-based (FEAT-022 Non-Functional / Byte-based enforcement).
20	type Caps struct {
21		MaxPromptBytes       int
22		MaxInlinedFileBytes  int
23		MaxDiffBytes         int
24		MaxGoverningDocBytes int
25	}
26	
27	// DefaultCaps returns the built-in conservative defaults.
28	func DefaultCaps() Caps {
29		return Caps{
30			MaxPromptBytes:       DefaultMaxPromptBytes,
31			MaxInlinedFileBytes:  DefaultMaxInlinedFileBytes,
32			MaxDiffBytes:         DefaultMaxDiffBytes,
33			MaxGoverningDocBytes: DefaultMaxGoverningDocBytes,
34		}
35	}
36	
37	// CapsOverride is the partial-override shape that .ddx/config.yaml
38	// expresses. A nil pointer means "fall through to the next layer".
39	type CapsOverride struct {
40		MaxPromptBytes       *int
41		MaxInlinedFileBytes  *int
42		MaxDiffBytes         *int
43		MaxGoverningDocBytes *int
44	}
45	
46	// Apply layers an override onto a Caps value, returning the resolved Caps.
47	// Nil fields in the override leave the corresponding cap unchanged.
48	func (c Caps) Apply(o CapsOverride) Caps {
49		if o.MaxPromptBytes != nil {
50			c.MaxPromptBytes = *o.MaxPromptBytes
51		}
52		if o.MaxInlinedFileBytes != nil {
53			c.MaxInlinedFileBytes = *o.MaxInlinedFileBytes
54		}
55		if o.MaxDiffBytes != nil {
56			c.MaxDiffBytes = *o.MaxDiffBytes
57		}
58		if o.MaxGoverningDocBytes != nil {
59			c.MaxGoverningDocBytes = *o.MaxGoverningDocBytes
60		}
61		return c
62	}
63	
64	// ResolveCaps resolves the effective caps for an invocation given a
65	// project-wide override and an optional per-harness override. Precedence
66	// (low → high): defaults < project-wide < per-harness.
67	//
68	// harness == "" or absence in perHarness means no per-harness layer.
69	// A missing project override is expressed as a zero-value CapsOverride.
70	func ResolveCaps(project CapsOverride, perHarness map[string]CapsOverride, harness string) Caps {
71		caps := DefaultCaps().Apply(project)
72		if harness != "" && perHarness != nil {
73			if h, ok := perHarness[harness]; ok {
74				caps = caps.Apply(h)
75			}
76		}
77		return caps
78	}
