1834	func (s *Server) handleExecDispatch(w http.ResponseWriter, r *http.Request) {
1835		if !isTrusted(r) {
1836			writeJSON(w, http.StatusForbidden, map[string]string{"error": "dispatch endpoints are localhost-only"})
1837			return
1838		}
1839	
1840		id := r.PathValue("id")
1841		if id == "" {
1842			writeJSON(w, http.StatusBadRequest, map[string]string{"error": "definition id is required"})
1843			return
1844		}
1845	
1846		store := s.execStoreForRequest(r)
1847		record, err := store.Run(r.Context(), id)
1848		if err != nil {
1849			writeJSON(w, http.StatusInternalServerError, map[string]string{"error": err.Error()})
1850			return
