1896	func (s *Server) handleAgentWorkers(w http.ResponseWriter, r *http.Request) {
1897		// Scoped/singleton: return workers for just the resolved project.
1898		if _, ok := projectFromContext(r.Context()); ok {
1899			m := s.workerManagerForRequest(r)
1900			recs, err := m.List()
1901			if err != nil {
1902				writeJSON(w, http.StatusOK, []WorkerRecord{})
1903				return
1904			}
1905			sort.Slice(recs, func(i, j int) bool {
1906				return recs[i].StartedAt.After(recs[j].StartedAt)
1907			})
1908			writeJSON(w, http.StatusOK, recs)
1909			return
1910		}
1911	
1912		projects := s.state.GetProjects()
1913	
1914		var all []WorkerRecord
1915		seen := map[string]bool{}
1916	
1917		for _, proj := range projects {
1918			var m *WorkerManager
1919			if proj.Path == s.WorkingDir {
1920				m = s.workers
1921			} else {
1922				m = NewWorkerManager(proj.Path)
1923			}
1924			recs, err := m.List()
1925			if err != nil {
1926				continue
1927			}
1928			for _, rec := range recs {
1929				if !seen[rec.ID] {
1930					all = append(all, rec)
1931					seen[rec.ID] = true
1932				}
1933			}
1934		}
1935	
1936		sort.Slice(all, func(i, j int) bool {
1937			return all[i].StartedAt.After(all[j].StartedAt)
1938		})
1939	
1940		writeJSON(w, http.StatusOK, all)
1941	}
