99	func findDefinitionByID(defs []Definition, definitionID string) (Definition, error) {
100		var (
101			best  Definition
102			found bool
103		)
104		for _, def := range defs {
105			if def.ID != definitionID {
106				continue
107			}
108			if !found || def.CreatedAt.After(best.CreatedAt) || (def.CreatedAt.Equal(best.CreatedAt) && def.ID > best.ID) {
109				best = def
110				found = true
111			}
112		}
113		if !found {
114			return Definition{}, fmt.Errorf("exec definition for %q not found", definitionID)
115		}
116		if best.ID == "" {
117			return Definition{}, fmt.Errorf("exec definition for %q is missing id", definitionID)
118		}
119		return best, nil
120	}
