130	func (s *Store) Validate(definitionID string) (*Definition, *docgraph.Document, error) {
131		defs, graph, err := s.loadDefinitions()
132		if err != nil {
133			return nil, nil, err
134		}
135		def, err := findDefinitionByID(defs, definitionID)
136		if err != nil {
137			return nil, nil, err
138		}
139		if def.ID == "" {
140			return nil, nil, fmt.Errorf("exec definition is missing id")
141		}
142		if len(def.ArtifactIDs) == 0 {
143			return nil, nil, fmt.Errorf("exec definition %q has no artifact_ids", def.ID)
144		}
145		if def.Executor.Kind != ExecutorKindCommand && def.Executor.Kind != ExecutorKindAgent {
146			return nil, nil, fmt.Errorf("exec definition %q has invalid executor kind %q", def.ID, def.Executor.Kind)
147		}
148		if def.Executor.Kind == ExecutorKindCommand && len(def.Executor.Command) == 0 {
149			return nil, nil, fmt.Errorf("exec definition %q has no command", def.ID)
150		}
151		if graph == nil {
152			graph, err = s.buildGraph()
153			if err != nil {
154				return nil, nil, err
155			}
156		}
157		var primary *docgraph.Document
158		for _, artifactID := range def.ArtifactIDs {
159			doc, ok := graph.Show(artifactID)
160			if !ok {
161				return nil, nil, fmt.Errorf("exec definition %q references missing artifact %q", def.ID, artifactID)
162			}
163			if primary == nil {
164				docCopy := doc
165				primary = &docCopy
166			}
167		}
168		return &def, primary, nil
169	}
