363	func (s *Store) History(artifactID, definitionID string) ([]RunRecord, error) {
364		entries, err := s.loadRuns()
365		if err != nil {
366			return nil, err
367		}
368		filtered := make([]RunRecord, 0, len(entries))
369		for _, rec := range entries {
370			if artifactID != "" && !containsString(rec.ArtifactIDs, artifactID) {
371				continue
372			}
373			if definitionID != "" && rec.DefinitionID != definitionID {
374				continue
375			}
376			filtered = append(filtered, rec)
377		}
378		return filtered, nil
379	}
