407	func (s *Store) writeRunBundle(rec RunRecord) error {
408		if err := os.MkdirAll(s.RunsDir, 0o755); err != nil {
409			return err
410		}
411		tempDir, err := os.MkdirTemp(s.RunsDir, ".tmp-")
412		if err != nil {
413			return err
414		}
415		defer os.RemoveAll(tempDir)
416	
417		manifestRaw, err := json.MarshalIndent(rec.RunManifest, "", "  ")
418		if err != nil {
419			return err
420		}
421		resultRaw, err := json.MarshalIndent(rec.Result, "", "  ")
422		if err != nil {
423			return err
424		}
425		if err := os.WriteFile(filepath.Join(tempDir, "manifest.json"), manifestRaw, 0o644); err != nil {
426			return err
427		}
428		if err := os.WriteFile(filepath.Join(tempDir, "result.json"), resultRaw, 0o644); err != nil {
429			return err
430		}
431		if err := os.WriteFile(filepath.Join(tempDir, "stdout.log"), []byte(rec.Result.Stdout), 0o644); err != nil {
432			return err
433		}
434		if err := os.WriteFile(filepath.Join(tempDir, "stderr.log"), []byte(rec.Result.Stderr), 0o644); err != nil {
435			return err
436		}
437		if err := syncPath(tempDir); err != nil {
438			return err
439		}
440		finalDir := filepath.Join(s.RunsDir, rec.RunID)
441		if err := os.Rename(tempDir, finalDir); err != nil {
442			return err
443		}
444		return syncPath(s.RunsDir)
445	}
