452		resultRaw, err := os.ReadFile(filepath.Join(dir, "result.json"))
453		if err != nil {
454			return RunRecord{}, err
455		}
456		var manifest RunManifest
457		if err := json.Unmarshal(manifestRaw, &manifest); err != nil {
458			return RunRecord{}, err
459		}
460		var result RunResult
461		if err := json.Unmarshal(resultRaw, &result); err != nil {
462			return RunRecord{}, err
463		}
464		return RunRecord{RunManifest: manifest, Result: result}, nil
465	}
