549	func normalizeMeasurement(stdout string) (float64, string) {
550		trimmed := strings.TrimSpace(stdout)
551		if trimmed == "" {
552			return 0, ""
553		}
554		if value, unit, ok := parseJSONMeasurement(trimmed); ok {
555			return value, unit
556		}
557		if value, unit, ok := parseTextMeasurement(trimmed); ok {
558			return value, unit
559		}
560		return 0, ""
561	}
562	
563	func parseJSONMeasurement(text string) (float64, string, bool) {
564		var obj map[string]any
565		if err := json.Unmarshal([]byte(text), &obj); err != nil {
566			return 0, "", false
567		}
568		if raw, ok := obj["value"]; ok {
569			switch v := raw.(type) {
570			case float64:
571				unit, _ := obj["unit"].(string)
572				return v, unit, true
573			case string:
574				if parsed, err := strconv.ParseFloat(v, 64); err == nil {
575					unit, _ := obj["unit"].(string)
576					return parsed, unit, true
577				}
578			}
579		}
580		return 0, "", false
581	}
582	
583	func parseTextMeasurement(text string) (float64, string, bool) {
584		match := measurementPattern.FindStringSubmatch(text)
585		if len(match) < 2 {
586			return 0, "", false
587		}
588		value, err := strconv.ParseFloat(match[1], 64)
589		if err != nil {
590			return 0, "", false
591		}
592		unit := ""
593		if len(match) >= 3 {
594			unit = strings.ToLower(match[2])
595		}
596		return value, unit, true
597	}
