15	// loadDefinitions returns all definitions and the doc graph built during loading.
16	// The graph may be nil if graph loading failed (soft error treated as empty).
17	func (s *Store) loadDefinitions() ([]Definition, *docgraph.Graph, error) {
18		defs := make(map[string]Definition)
19	
20		// Graph-authored definitions take precedence over runtime-managed ones.
21		// The graph is returned so callers can reuse it without a second build.
22		graph, graphDefs, _ := s.loadGraphDefinitions()
23		for _, def := range graphDefs {
24			if def.ID == "" || !def.Active {
25				continue
26			}
27			defs[def.ID] = def
28		}
29	
30		if s.DefinitionCollection != nil {
31			beads, err := s.DefinitionCollection.ReadAll()
32			if err != nil {
33				return nil, nil, err
34			}
35			for _, entry := range beads {
36				def, err := definitionFromBead(entry)
37				if err != nil {
38					return nil, nil, err
39				}
40				if def.ID == "" || !def.Active {
41					continue
42				}
43				if _, ok := defs[def.ID]; ok {
44					continue // graph-authored takes precedence
45				}
46				defs[def.ID] = def
47			}
48		}
49	
50		legacy, err := s.readLegacyDefinitions()
51		if err != nil {
52			return nil, nil, err
53		}
54		for _, def := range legacy {
55			if def.ID == "" || !def.Active {
56				continue
57			}
58			if _, ok := defs[def.ID]; ok {
59				continue
60			}
61			defs[def.ID] = def
62		}
63	
64		out := make([]Definition, 0, len(defs))
65		for _, def := range defs {
66			out = append(out, def)
67		}
68		sort.Slice(out, func(i, j int) bool {
69			if out[i].CreatedAt.Equal(out[j].CreatedAt) {
70				return out[i].ID < out[j].ID
71			}
72			return out[i].CreatedAt.After(out[j].CreatedAt)
73		})
74		return out, graph, nil
75	}
