77	// loadGraphDefinitions builds the doc graph and extracts exec definitions
78	// embedded in document frontmatter via the exec: block.
79	// Returns the built graph so callers can reuse it without a second walk.
80	func (s *Store) loadGraphDefinitions() (*docgraph.Graph, []Definition, error) {
81		graph, err := s.buildGraph()
82		if err != nil {
83			return nil, nil, err
84		}
85		var defs []Definition
86		for _, doc := range graph.Documents {
87			if doc.ExecDef == nil {
88				continue
89			}
90			ed := doc.ExecDef
91			// ArtifactIDs: prefer the explicit list; fall back to the document's depends_on.
92			artifactIDs := append([]string{}, ed.ArtifactIDs...)
93			if len(artifactIDs) == 0 {
94				artifactIDs = append(artifactIDs, doc.DependsOn...)
95			}
96			def := Definition{
97				ID:          doc.ID,
98				ArtifactIDs: artifactIDs,
99				Executor: ExecutorSpec{
100					Kind:      ed.Kind,
101					Command:   ed.Command,
102					Cwd:       ed.Cwd,
103					Env:       ed.Env,
104					TimeoutMS: ed.TimeoutMS,
105				},
106				Required:    ed.Required,
107				Active:      ed.Active,
108				GraphSource: true,
109			}
110			if ed.Comparison != "" || ed.Thresholds != nil {
111				def.Evaluation = Evaluation{Comparison: ed.Comparison}
112				if ed.Thresholds != nil {
113					def.Evaluation.Thresholds = Thresholds{
114						WarnMS:    ed.Thresholds.Warn,
115						RatchetMS: ed.Thresholds.Ratchet,
116					}
117				}
118			}
119			if ed.Metric != nil {
120				def.Result.Metric = &MetricResultSpec{
121					Unit: ed.Metric.Unit,
122				}
123			}
124			defs = append(defs, def)
125		}
126		return graph, defs, nil
127	}
