174		}
175	
176		legacy, err := s.readLegacyRuns()
177		if err != nil {
178			return nil, err
179		}
180		for _, rec := range legacy {
181			if rec.RunID == "" {
182				continue
183			}
184			if _, ok := runs[rec.RunID]; ok {
185				continue
186			}
187			runs[rec.RunID] = rec
