242	func definitionBead(def Definition) bead.Bead {
243		title := def.ID
244		if len(def.ArtifactIDs) > 0 {
245			title = fmt.Sprintf("Execution definition for %s", strings.Join(def.ArtifactIDs, ", "))
246		}
247		status := bead.StatusClosed
248		if def.Active {
249			status = bead.StatusOpen
250		}
251		return bead.Bead{
252			ID:        def.ID,
253			Title:     title,
254			Status:    status,
255			Priority:  2,
256			IssueType: "exec_definition",
257			CreatedAt: def.CreatedAt,
258			UpdatedAt: def.CreatedAt,
259			Labels:    definitionLabels(def),
260			Extra: map[string]any{
261				"definition": def,
262			},
263		}
264	}
