266	func definitionFromBead(b bead.Bead) (Definition, error) {
267		var def Definition
268		if raw, ok := b.Extra["definition"]; ok {
269			if err := decodeAny(raw, &def); err != nil {
270				return Definition{}, err
271			}
272		}
273		if def.ID == "" {
274			def.ID = b.ID
275		}
276		if def.CreatedAt.IsZero() {
277			def.CreatedAt = b.CreatedAt
278		}
279		if !def.Active {
280			def.Active = b.Status == bead.StatusOpen
281		}
282		if len(def.ArtifactIDs) == 0 {
283			def.ArtifactIDs = beadArtifactIDs(b)
284		}
285		return def, nil
286	}
