308	func (s *Store) runRecordFromBead(b bead.Bead) (RunRecord, error) {
309		var manifest RunManifest
310		if raw, ok := b.Extra["manifest"]; ok {
311			if err := decodeAny(raw, &manifest); err != nil {
312				return RunRecord{}, err
313			}
314		}
315		if manifest.RunID == "" {
316			manifest.RunID = b.ID
317		}
318		if len(manifest.ArtifactIDs) == 0 {
319			manifest.ArtifactIDs = beadArtifactIDs(b)
320		}
321		if manifest.StartedAt.IsZero() {
322			manifest.StartedAt = b.CreatedAt
323		}
324		if manifest.FinishedAt.IsZero() {
325			manifest.FinishedAt = b.UpdatedAt
326		}
327		if manifest.Status == "" {
328			manifest.Status = beadRunStatus(b.Status)
329		}
330		if manifest.Attachments == nil {
331			manifest.Attachments = runAttachmentRefs(s.WorkingDir, manifest.RunID)
332		}
333	
334		result, err := s.readRunResult(manifest)
335		if err != nil {
336			return RunRecord{}, err
337		}
338		return RunRecord{RunManifest: manifest, Result: result}, nil
339	}
