364	func (s *Store) saveDefinitionBead(def Definition) error {
365		if s.DefinitionCollection == nil {
366			return fmt.Errorf("exec definition collection not initialized")
367		}
368		return s.DefinitionCollection.WithLock(func() error {
369			beads, err := s.DefinitionCollection.ReadAll()
370			if err != nil {
371				return err
372			}
373			current := definitionBead(def)
374			replaced := false
375			for i := range beads {
376				if beads[i].ID == current.ID {
377					beads[i] = current
378					replaced = true
379					break
380				}
381			}
382			if !replaced {
383				beads = append(beads, current)
384			}
385			return s.DefinitionCollection.WriteAll(beads)
386		})
387	}
