389	func (s *Store) saveRunRecord(rec RunRecord) error {
390		if s.RunCollection == nil {
391			return fmt.Errorf("exec run collection not initialized")
392		}
393		if rec.RunID == "" {
394			return fmt.Errorf("run_id is required")
395		}
396		if rec.DefinitionID == "" {
397			return fmt.Errorf("definition_id is required")
398		}
399		if rec.Attachments == nil {
400			rec.Attachments = make(map[string]string)
401		}
402		rec.Attachments["stdout"] = runAttachmentRef(s.WorkingDir, rec.RunID, "stdout.log")
403		rec.Attachments["stderr"] = runAttachmentRef(s.WorkingDir, rec.RunID, "stderr.log")
404		rec.Attachments["result"] = runAttachmentRef(s.WorkingDir, rec.RunID, "result.json")
405	
406		attachmentRoot := filepath.Join(s.WorkingDir, ".ddx", execRunAttachmentDir)
407		if err := os.MkdirAll(attachmentRoot, 0o755); err != nil {
408			return err
409		}
410		tempDir, err := os.MkdirTemp(attachmentRoot, ".tmp-")
411		if err != nil {
412			return err
413		}
414		defer os.RemoveAll(tempDir)
415	
416		manifestRaw, err := json.MarshalIndent(rec.RunManifest, "", "  ")
417		if err != nil {
418			return err
419		}
420		resultRaw, err := json.MarshalIndent(rec.Result, "", "  ")
421		if err != nil {
422			return err
423		}
424		if err := os.WriteFile(filepath.Join(tempDir, "manifest.json"), manifestRaw, 0o644); err != nil {
425			return err
426		}
427		if err := os.WriteFile(filepath.Join(tempDir, "result.json"), resultRaw, 0o644); err != nil {
428			return err
429		}
430		if err := os.WriteFile(filepath.Join(tempDir, "stdout.log"), []byte(rec.Result.Stdout), 0o644); err != nil {
431			return err
432		}
433		if err := os.WriteFile(filepath.Join(tempDir, "stderr.log"), []byte(rec.Result.Stderr), 0o644); err != nil {
434			return err
435		}
436		if err := syncPath(tempDir); err != nil {
437			return err
438		}
439	
440		return s.RunCollection.WithLock(func() error {
441			finalDir := filepath.Join(attachmentRoot, rec.RunID)
442			if err := os.Rename(tempDir, finalDir); err != nil {
443				return err
444			}
445			if err := syncPath(attachmentRoot); err != nil {
446				return err
447			}
448			beads, err := s.RunCollection.ReadAll()
449			if err != nil {
450				return err
451			}
452			current := runBead(rec)
453			replaced := false
454			for i := range beads {
455				if beads[i].ID == current.ID {
456					beads[i] = current
457					replaced = true
458					break
459				}
460			}
461			if !replaced {
462				beads = append(beads, current)
463			}
464			return s.RunCollection.WriteAll(beads)
465		})
466	}
