561	func (g *Graph) detectCycles() {
562		index := 0
563		indexes := map[string]int{}
564		lowlinks := map[string]int{}
565		onStack := map[string]bool{}
566		stack := []string{}
567		warned := map[string]struct{}{}
568		var visit func(string)
569	
570		visit = func(id string) {
571			indexes[id] = index
572			lowlinks[id] = index
573			index++
574			stack = append(stack, id)
575			onStack[id] = true
576	
577			node := g.Documents[id]
578			for _, dep := range node.DependsOn {
579				if _, ok := g.Documents[dep]; !ok {
580					continue
581				}
582				if _, ok := indexes[dep]; !ok {
583					visit(dep)
584					if lowlinks[dep] < lowlinks[id] {
585						lowlinks[id] = lowlinks[dep]
586					}
587				} else if onStack[dep] {
588					if indexes[dep] < lowlinks[id] {
589						lowlinks[id] = indexes[dep]
590					}
591				}
592			}
593	
594			if lowlinks[id] == indexes[id] {
595				cycle := []string{}
596				for {
