23	// DocExecDef describes an execution definition embedded in a graph document.
24	// The YAML key is "execution" (matching the ddx: frontmatter convention).
25	// Fields are flat to match the authored document format:
26	//
27	//	ddx:
28	//	  execution:
29	//	    kind: command
30	//	    required: true
31	//	    command: ["make", "test"]
32	//	    cwd: cli
33	//	    timeout_ms: 120000
34	//	    comparison: lower-is-better
35	//	    thresholds:
36	//	      ratchet: 250
37	//	      unit: ms
38	//	    metric:
39	//	      metric_id: MET-API-LATENCY
40	//
41	// ArtifactIDs is optional; when absent, the document's depends_on list is used
42	// to determine which artifacts this execution is linked to. Comparison,
43	// Thresholds, and Metric declare the ratchet evaluation applied by the
44	// landing gate when the command exits 0: the gate parses a numeric observed
45	// value out of stdout and compares it against the ratchet threshold before
46	// allowing the attempt to merge.
47	type DocExecDef struct {
48		Kind        string            `yaml:"kind"`
49		Command     []string          `yaml:"command"`
50		Cwd         string            `yaml:"cwd"`
51		Env         map[string]string `yaml:"env"`
52		TimeoutMS   int               `yaml:"timeout_ms"`
53		ArtifactIDs []string          `yaml:"artifact_ids"`
54		Required    bool              `yaml:"required"`
55		Active      bool              `yaml:"active"`
56		Comparison  string            `yaml:"comparison"`
