94	// ParseFrontmatter parses YAML frontmatter from markdown content.
95	// It reads both ddx: and dun: namespaces (preferring ddx: if both present).
96	// Returns the parsed frontmatter, the body text after the closing ---, and any error.
97	func ParseFrontmatter(content []byte) (Frontmatter, string, error) {
98		frontmatterText, body, ok := splitFrontmatter(content)
99		if !ok {
100			return Frontmatter{}, string(content), nil
101		}
102	
103		trimmed := strings.TrimSpace(frontmatterText)
104	
105		// Try ddx: first, then dun: for backward compatibility
106		var doc DocFrontmatter
107		namespace := ""
108	
109		var ddxWrapper struct {
110			DDx DocFrontmatter `yaml:"ddx"`
111		}
112		if err := yaml.Unmarshal([]byte(trimmed), &ddxWrapper); err != nil {
113			return Frontmatter{}, "", fmt.Errorf("parse frontmatter: %w", err)
114		}
115		if ddxWrapper.DDx.ID != "" {
116			doc = ddxWrapper.DDx
117			namespace = "ddx"
118		} else {
119			var dunWrapper struct {
120				Dun DocFrontmatter `yaml:"dun"`
121			}
122			if err := yaml.Unmarshal([]byte(trimmed), &dunWrapper); err != nil {
123				return Frontmatter{}, "", fmt.Errorf("parse frontmatter: %w", err)
124			}
125			if dunWrapper.Dun.ID != "" {
126				doc = dunWrapper.Dun
127				namespace = "dun"
128			}
129		}
130	
131		var node yaml.Node
132		if err := yaml.Unmarshal([]byte(trimmed), &node); err != nil {
133			return Frontmatter{}, "", fmt.Errorf("parse frontmatter node: %w", err)
134		}
135	
136		var root *yaml.Node
137		if len(node.Content) > 0 {
138			root = node.Content[0]
139		}
140	
141		return Frontmatter{
142			Doc:            doc,
143			Raw:            root,
144			HasFrontmatter: true,
145			Namespace:      namespace,
146		}, body, nil
147	}
