149	// MigrateLegacyDunFrontmatter converts top-level `dun:` metadata to `ddx:`.
150	//
151	// Migration is lossless for fields:
152	//   - If both `ddx` and `dun` are present, keys from `dun` are merged into `ddx`
153	//     when missing.
154	//   - If only `dun` is present, it is renamed to `ddx`.
155	//   - If `ddx` is already present and no other legacy-compatible namespace exists,
156	//     no changes are made.
157	func MigrateLegacyDunFrontmatter(root *yaml.Node) bool {
158		if root == nil || root.Kind != yaml.MappingNode {
159			return false
160		}
161	
162		ddxNode := findMappingValue(root, "ddx")
163		dunNode := findMappingValue(root, "dun")
164		if dunNode == nil {
165			return false
166		}
167	
168		if ddxNode == nil {
169			dunKey := findMappingKey(root, "dun")
170			if dunKey != nil {
171				dunKey.Value = "ddx"
172			}
173			return true
174		}
175	
176		// Merge legacy keys into ddx only when missing.
177		mergeIntoDDX(ddxNode, dunNode)
178	
179		removeMappingKey(root, "dun")
180		return true
181	}
