224	// SetReview updates the review block in the frontmatter YAML node.
225	// Always writes under the ddx: namespace.
226	func SetReview(root *yaml.Node, review DocReview) error {
227		if root == nil {
228			return fmt.Errorf("frontmatter missing")
229		}
230		if root.Kind != yaml.MappingNode {
231			return fmt.Errorf("frontmatter root must be mapping")
232		}
233	
234		// Ensure ddx: namespace exists; if only dun: exists, create ddx:
235		ddxNode := findMappingValue(root, "ddx")
236		if ddxNode == nil {
237			// Copy from dun: if it exists, then write as ddx:
238			dunNode := findMappingValue(root, "dun")
239			if dunNode != nil {
240				ddxNode = ensureMappingNode(root, "ddx")
241				// Copy content from dun to ddx
242				ddxNode.Content = append(ddxNode.Content[:0], dunNode.Content...)
243				// Remove dun: namespace
244				removeMappingKey(root, "dun")
245			} else {
246				ddxNode = ensureMappingNode(root, "ddx")
247			}
248		}
249	
250		reviewNode := ensureMappingNode(ddxNode, "review")
251		setScalarNode(reviewNode, "self_hash", review.SelfHash)
252		setMappingNode(reviewNode, "deps", review.Deps)
253		if review.ReviewedAt != "" {
254			setScalarNode(reviewNode, "reviewed_at", review.ReviewedAt)
255		}
256		return nil
257	}
