276	func ensureMappingNode(parent *yaml.Node, key string) *yaml.Node {
277		if parent.Kind != yaml.MappingNode {
278			parent.Kind = yaml.MappingNode
279		}
280		for i := 0; i < len(parent.Content); i += 2 {
281			k := parent.Content[i]
282			if k.Value == key {
283				v := parent.Content[i+1]
284				if v.Kind != yaml.MappingNode {
285					v.Kind = yaml.MappingNode
286					v.Content = nil
287				}
288				return v
289			}
290		}
291		keyNode := &yaml.Node{Kind: yaml.ScalarNode, Tag: "!!str", Value: key}
292		valueNode := &yaml.Node{Kind: yaml.MappingNode}
293		parent.Content = append(parent.Content, keyNode, valueNode)
294		return valueNode
295	}
296	
297	func setScalarNode(parent *yaml.Node, key string, value string) {
298		for i := 0; i < len(parent.Content); i += 2 {
299			k := parent.Content[i]
300			if k.Value == key {
301				parent.Content[i+1] = &yaml.Node{Kind: yaml.ScalarNode, Tag: "!!str", Value: value}
302				return
303			}
304		}
305		parent.Content = append(parent.Content,
306			&yaml.Node{Kind: yaml.ScalarNode, Tag: "!!str", Value: key},
307			&yaml.Node{Kind: yaml.ScalarNode, Tag: "!!str", Value: value},
308		)
309	}
310	
311	func setMappingNode(parent *yaml.Node, key string, values map[string]string) {
312		mapping := &yaml.Node{Kind: yaml.MappingNode}
313		if len(values) > 0 {
314			keys := make([]string, 0, len(values))
315			for k := range values {
316				keys = append(keys, k)
317			}
318			sort.Strings(keys)
319			for _, k := range keys {
320				mapping.Content = append(mapping.Content,
321					&yaml.Node{Kind: yaml.ScalarNode, Tag: "!!str", Value: k},
322					&yaml.Node{Kind: yaml.ScalarNode, Tag: "!!str", Value: values[k]},
323				)
324			}
325		}
326		for i := 0; i < len(parent.Content); i += 2 {
327			k := parent.Content[i]
328			if k.Value == key {
329				parent.Content[i+1] = mapping
330				return
331			}
332		}
333		parent.Content = append(parent.Content,
334			&yaml.Node{Kind: yaml.ScalarNode, Tag: "!!str", Value: key},
335			mapping,
336		)
337	}
