339	func findMappingValue(node *yaml.Node, key string) *yaml.Node {
340		if node == nil || node.Kind != yaml.MappingNode {
341			return nil
342		}
343		for i := 0; i < len(node.Content); i += 2 {
344			k := node.Content[i]
345			if k.Value == key {
346				return node.Content[i+1]
347			}
348		}
349		return nil
350	}
