365	func mergeIntoDDX(ddxNode *yaml.Node, dunNode *yaml.Node) {
366		if ddxNode == nil || dunNode == nil {
367			return
368		}
369		if ddxNode.Kind != yaml.MappingNode {
370			ddxNode.Kind = yaml.MappingNode
371		}
372		if dunNode.Kind != yaml.MappingNode {
373			return
374		}
375	
376		existing := map[string]struct{}{}
377		for i := 0; i < len(ddxNode.Content); i += 2 {
378			existing[ddxNode.Content[i].Value] = struct{}{}
379		}
380	
381		merged := false
382		for i := 0; i < len(dunNode.Content); i += 2 {
383			keyNode := dunNode.Content[i]
384			valNode := dunNode.Content[i+1]
385			if keyNode == nil || valNode == nil {
386				continue
387			}
388			if _, ok := existing[keyNode.Value]; ok {
389				continue
390			}
391			clonedValue := cloneNode(valNode)
392			ddxNode.Content = append(ddxNode.Content, &yaml.Node{
393				Kind:  keyNode.Kind,
394				Tag:   keyNode.Tag,
395				Value: keyNode.Value,
396			}, clonedValue)
397			existing[keyNode.Value] = struct{}{}
398			merged = true
399		}
400		if merged {
401			sortMappingNodes(ddxNode)
402		}
403	}
404	
405	func removeMappingKey(node *yaml.Node, key string) {
406		if node == nil || node.Kind != yaml.MappingNode {
407			return
408		}
409		for i := 0; i < len(node.Content); i += 2 {
410			k := node.Content[i]
411			if k.Value == key {
412				node.Content = append(node.Content[:i], node.Content[i+2:]...)
413				return
414			}
415		}
416	}
