168	func buildGraph(workingDir string, roots []string) (*Graph, error) {
169		files, err := findMarkdownFiles(workingDir, roots)
170		if err != nil {
171			return nil, err
172		}
173	
174		cleanRoot := filepath.Clean(workingDir)
175		documents := make(map[string]*Document)
176		pathToID := make(map[string]string)
177		issues := []GraphIssue{}
178		for _, filePath := range files {
179			doc, err := ParseDocument(filePath)
180			if err != nil {
181				if errors.Is(err, ErrNotDocGraphDocument) {
182					continue
183				}
184				issues = append(issues, GraphIssue{
185					Kind:    IssueParseError,
186					Path:    relPath(cleanRoot, filePath),
187					Message: fmt.Sprintf("%s: %v", filePath, err),
188				})
189				continue
190			}
191			if existing, exists := documents[doc.ID]; exists {
192				issues = append(issues, GraphIssue{
193					Kind:        IssueDuplicateID,
194					Path:        relPath(cleanRoot, filePath),
195					ID:          doc.ID,
196					Message:     fmt.Sprintf("duplicate document id %q in %q", doc.ID, filePath),
197					RelatedPath: existing.Path,
198				})
199				continue
200			}
201			doc.Path = relPath(cleanRoot, filePath)
202			documents[doc.ID] = doc
203			pathToID[doc.Path] = doc.ID
204		}
205	
206		g := &Graph{
207			RootDir:   cleanRoot,
208			Documents: documents,
209			PathToID:  pathToID,
210			Issues:    issues,
211		}
212		g.resolveBodyLinks()
213		g.buildDependents()
214		g.detectMissingDeps()
215		g.detectCycles()
216		g.applyConfigDefaults()
217		g.finalizeWarnings()
218		return g, nil
219	}
