221	// detectMissingDeps emits missing_dep issues for every declared dependency
222	// that does not resolve to a document in the graph. Runs after body-link
223	// resolution so link targets are already promoted to DependsOn.
224	func (g *Graph) detectMissingDeps() {
225		for _, id := range sortedDocIDs(g.Documents) {
226			doc := g.Documents[id]
227			if doc == nil {
228				continue
229			}
230			for _, dep := range doc.DependsOn {
231				if _, ok := g.Documents[dep]; ok {
232					continue
233				}
234				g.Issues = append(g.Issues, GraphIssue{
235					Kind:    IssueMissingDep,
236					Path:    doc.Path,
237					ID:      dep,
238					Message: fmt.Sprintf("document %q declares dependency %q which is not in the graph", doc.ID, dep),
239				})
240			}
241		}
242	}
