244	// sortedDocIDs returns the IDs of docs sorted for stable issue ordering.
245	func sortedDocIDs(docs map[string]*Document) []string {
246		ids := make([]string, 0, len(docs))
247		for id := range docs {
248			ids = append(ids, id)
249		}
250		sort.Strings(ids)
251		return ids
