179	// TestPromptIngressEvidencePrimitiveUsage is the AST gate that prevents
180	// future drift: every os.ReadFile / ioutil.ReadFile call inside the
181	// in-scope agent files whose argument names a "*PromptFile" symbol
182	// must either route through evidence (readPromptFileBounded /
183	// evidence.ReadFileClamped) or carry an //evidence:allow-unbounded
184	// annotation.
185	func TestPromptIngressEvidencePrimitiveUsage(t *testing.T) {
186		files := []string{
187			"runner.go",
188			"compare_adapter.go",
189			"service_run.go",
190			"execute_bead.go",
191		}
192	
193		for _, src := range files {
194			t.Run(src, func(t *testing.T) {
195				fset := token.NewFileSet()
196				file, err := parser.ParseFile(fset, src, nil, parser.ParseComments)
197				if err != nil {
198					t.Fatalf("parse %s: %v", src, err)
199				}
200	
201				hasAllow := func(node ast.Node) bool {
202					nodePos := fset.Position(node.Pos())
203					for _, cg := range file.Comments {
204						cgEnd := fset.Position(cg.End())
205						if cgEnd.Filename != nodePos.Filename {
206							continue
207						}
208						if cgEnd.Line >= nodePos.Line-3 && cgEnd.Line < nodePos.Line {
209							for _, c := range cg.List {
210								if strings.Contains(c.Text, "evidence:allow-unbounded") {
211									return true
212								}
213							}
214						}
215					}
216					return false
217				}
218	
219				var violations []string
220				ast.Inspect(file, func(n ast.Node) bool {
221					call, ok := n.(*ast.CallExpr)
222					if !ok {
223						return true
224					}
225					sel, ok := call.Fun.(*ast.SelectorExpr)
226					if !ok {
227						return true
228					}
229					ident, ok := sel.X.(*ast.Ident)
230					if !ok {
231						return true
232					}
233					readFile := (ident.Name == "os" && sel.Sel.Name == "ReadFile") ||
234						(ident.Name == "ioutil" && sel.Sel.Name == "ReadFile")
235					if !readFile || len(call.Args) == 0 {
236						return true
237					}
238					// Identify --prompt-file-style arguments. We match selector
239					// expressions whose right-hand side is "PromptFile" (e.g.
240					// opts.PromptFile, prompt.PromptFile). These are the symbols
241					// Stage D1 routes through readPromptFileBounded.
242					argSel, ok := call.Args[0].(*ast.SelectorExpr)
243					if !ok {
244						return true
245					}
246					if argSel.Sel == nil || argSel.Sel.Name != "PromptFile" {
247						return true
248					}
249					if !hasAllow(call) {
250						p := fset.Position(call.Pos())
251						violations = append(violations,
252							fmt.Sprintf("%s: os.ReadFile(<*.PromptFile>) at line %d not routed through evidence", src, p.Line))
253					}
254					return true
255				})
256	
257				if len(violations) > 0 {
258					t.Errorf("FEAT-022 §8 violation(s):\n  %s",
259						strings.Join(violations, "\n  "))
260				}
261			})
262		}
263	}
